const items = [];
for (const item of $input.all()) {
  const email = item.json;
  const from = email.from?.text || email.from?.value?.[0]?.address || 'Unbekannt';
  const subject = email.subject || '(kein Betreff)';
  const snippet = (email.text || email.html || '').replace(/<[^>]+>/g, '').substring(0, 300);
  const messageId = email.messageId || `email-${Date.now()}`;

  items.push({
    json: {
      source: 'email',
      source_id: messageId,
      summary: `E-Mail von ${from}: ${subject}`,
      priority: subject.toLowerCase().includes('dringend') || subject.toLowerCase().includes('urgent') ? 'high' : 'medium',
      customer_id: $env.CUSTOMER_ID || null,
      buddy_id: $env.BUDDY_ID || null,
      timestamp: email.date || new Date().toISOString(),
      details: {
        from: from,
        subject: subject,
        snippet: snippet,
        has_attachment: (email.attachments || []).length > 0
      }
    }
  });
}
return items;
